sp_angular_provider.script:
/**
 * scmTableRowActionsSanitizer Service
 *
 * Provides centralized sanitization for row actions (href and target attributes)
 * on the client side. Complements server-side sanitization for defense-in-depth.
 */
function scmTableRowActionsSanitizer() {
    "use strict";

    function sanitizeHref(rawHref) {
        if (!rawHref) {
            return undefined;
        }

        var href = String(rawHref).trim();
        if (!href) {
            return undefined;
        }

        // Block explicitly unsafe schemes
        if (/^(javascript:|data:|vbscript:)/i.test(href)) {
            return undefined;
        }

        // Allow safe in-portal and relative routes
        if (
            href.indexOf("?") === 0 ||
            href.indexOf("/") === 0 ||
            href.indexOf("#") === 0
        ) {
            return href;
        }

        // Allow explicit safe schemes only
        if (/^(https?:|mailto:|tel:)/i.test(href)) {
            return href;
        }

        // Allow remaining non-schemed relative URLs like "id=contacts"
        if (!/^[a-zA-Z][a-zA-Z\d+.-]*:/.test(href)) {
            return href;
        }

        return undefined;
    }

    function sanitizeTarget(rawTarget) {
        var target = String(rawTarget || "_self").trim();
        var allowedTargets = {
            _self: true,
            _blank: true,
            _parent: true,
            _top: true,
        };

        return allowedTargets[target] ? target : "_self";
    }

    return {
        sanitizeHref: sanitizeHref,
        sanitizeTarget: sanitizeTarget,
    };
}
